  const controller = new AbortController()
  const timeout = new Promise<string>(resolve => {
    const t = setTimeout(() => {
      controller.abort()
      console.log('[neon-context] timeout — returning empty')
      resolve('')
    }, FETCH_TIMEOUT_MS)
    // Prevent the timeout from keeping the event loop alive
    if (t.unref) t.unref()
