/**
 * neon-context.ts — Runtime RAG context loader
 *
 * Pulls RY's family profiles, biography, and personal memories from Neon
 * at request time and returns a formatted context string for injection
 * into the system prompt.
 *
 * Caches the result for 1 hour using Vercel Runtime Cache so we don't
 * hammer the DB on every message.
 *
 * Requires: OMEGA_DB_URL env var (the Neon connection string).
 */

import { neon } from '@neondatabase/serverless'
import { getCache } from '@vercel/functions'

const CACHE_KEY = 'chyren:ry-context:v1'
const CACHE_TTL = 3600 // 1 hour

interface FamilyProfile {
  name: string
  last_name: string | null
  relationship: string
  location: string | null
  birthday: string | null
  deceased: boolean
  occupation: string | null
  partner: string | null
  children: string | null
  aliases: string[] | null
  ry_notes: string | null
  notes_for_omega: string | null
  how_to_greet: string | null
}

interface KnowledgeEntry {
  title: string
  content: string
  category: string
  importance: number
}

interface MemoryEntry {
  content: string
  importance: number
  domain: string | null
}

async function fetchContext(signal?: AbortSignal): Promise<string> {
  const url = process.env.OMEGA_DB_URL
  if (!url) return ''

  // Pass AbortSignal at the factory level so all queries are cancellable
  const sql = neon(url, signal ? { fetchOptions: { signal } } : {})

  const [familyRaw, knowledgeRaw, memoryRaw] = await Promise.all([
    sql`
      SELECT name, last_name, relationship, location, birthday, deceased,
             occupation, partner, children, aliases,
             ry_notes, notes_for_omega, how_to_greet
      FROM family_profiles
      ORDER BY id
    `,

    sql`
      SELECT title, content, category, importance
      FROM public_knowledge
      WHERE category IN ('biography', 'creator', 'concept', 'quote')
      ORDER BY importance DESC NULLS LAST
      LIMIT 25
    `,

    sql`
      SELECT content, importance, domain
      FROM omega_memory_entries
      WHERE namespace = 'personal'
        AND (superseded_by IS NULL OR superseded_by = '')
        AND content IS NOT NULL
        AND LENGTH(content) > 20
      ORDER BY importance DESC NULLS LAST
      LIMIT 20
    `,
  ])

  const familyRows = familyRaw as unknown as FamilyProfile[]
  const knowledgeRows = knowledgeRaw as unknown as KnowledgeEntry[]
  const memoryRows = memoryRaw as unknown as MemoryEntry[]

  const sections: string[] = []

  // Family profiles
  if (familyRows.length > 0) {
    const familyText = familyRows.map(p => {
      const fullName = [p.name, p.last_name].filter(Boolean).join(' ')
      const parts = [`${fullName} (${p.relationship})`]
      if (p.location) parts.push(`Location: ${p.location}`)
      if (p.birthday) parts.push(`Birthday: ${p.birthday}`)
      if (p.deceased) parts.push('Status: Deceased')
      if (p.occupation) parts.push(`Occupation: ${p.occupation}`)
      if (p.partner) parts.push(`Partner: ${p.partner}`)
      if (p.children) parts.push(`Children: ${p.children}`)
      if (p.aliases?.length) parts.push(`Also known as: ${p.aliases.join(', ')}`)
      if (p.how_to_greet) parts.push(`How to greet: ${p.how_to_greet}`)
      if (p.ry_notes) parts.push(`Notes from RY: ${p.ry_notes}`)
      if (p.notes_for_omega) parts.push(`Instructions: ${p.notes_for_omega}`)
      return parts.join('\n  ')
    }).join('\n\n')

    sections.push(`FAMILY PROFILES (${familyRows.length} members):\n${familyText}`)
  }

  // Biography / creator knowledge
  const bioRows = knowledgeRows.filter(r => ['biography', 'creator', 'concept'].includes(r.category))
  if (bioRows.length > 0) {
    const bioText = bioRows
      .map(r => `[${r.category.toUpperCase()}] ${r.title}: ${r.content}`)
      .join('\n\n')
    sections.push(`KNOWLEDGE ABOUT RY & OMEGA:\n${bioText}`)
  }

  // Canonical quotes
  const quotes = knowledgeRows.filter(r => r.category === 'quote')
  if (quotes.length > 0) {
    const quoteText = quotes.slice(0, 8).map(r => `"${r.content}" — ${r.title}`).join('\n')
    sections.push(`RY CANONICAL QUOTES:\n${quoteText}`)
  }

  // Personal memories
  if (memoryRows.length > 0) {
    const memText = memoryRows.map(r => r.content).join('\n')
    sections.push(`PERSONAL MEMORIES (high-importance):\n${memText}`)
  }

  if (sections.length === 0) return ''

  return `\n\n--- LIVE KNOWLEDGE CONTEXT (from Neon sovereign database) ---\n${sections.join('\n\n---\n')}\n--- END KNOWLEDGE CONTEXT ---`
}

const FETCH_TIMEOUT_MS = 2000 // abort DB query after 2s — never block streaming

/**
 * Returns the RAG context string for injection into the system prompt.
 * Cached for 1h. Returns empty string if OMEGA_DB_URL is not set or on error.
 * Hard abort after FETCH_TIMEOUT_MS — never blocks streaming.
 */
export async function getRYContext(): Promise<string> {
  // Try Vercel Runtime Cache first
  try {
    const cache = getCache()
    const cached = await Promise.race([
      cache.get(CACHE_KEY),
      new Promise<null>(r => setTimeout(() => r(null), 300)),
    ])
    if (cached && typeof cached === 'string') return cached
  } catch {
    // Runtime cache unavailable (local dev) — fall through
  }

  // Abort if DB takes too long — important: this actually cancels the HTTP request
  const controller = new AbortController()
  const timer = setTimeout(() => controller.abort(), FETCH_TIMEOUT_MS)

  try {
    const context = await fetchContext(controller.signal)
    clearTimeout(timer)

    // Store in cache fire-and-forget
    if (context) {
      void (async () => {
        try {
          const cache = getCache()
          await cache.set(CACHE_KEY, context, {
            ttl: CACHE_TTL,
            tags: ['ry-context'],
            name: 'ry-sovereign-context',
          })
        } catch { /* cache write not fatal */ }
      })()
    }

    return context
  } catch (err) {
    clearTimeout(timer)
    if ((err as Error)?.name !== 'AbortError') {
      console.error('[neon-context] Failed to fetch RY context:', err)
    }
    return ''
  }
}

/**
 * Force-invalidate the cached context (call after updating family profiles etc.)
 */
export async function invalidateRYContext(): Promise<void> {
  try {
    const cache = getCache()
    await cache.expireTag('ry-context')
  } catch {
    // Ignore
  }
}

/**
 * Fire-and-forget background warm-up. Call this early in a request handler
 * so the next request has the context ready in cache.
 */
export function warmRYContext(): void {
  void (async () => {
    try {
      const cache = getCache()
      // Check if already cached
      const cached = await Promise.race([
        cache.get(CACHE_KEY),
        new Promise<null>(r => setTimeout(() => r(null), 200)),
      ])
      if (cached) return

      // Fetch with generous timeout (background — no streaming to block)
      const controller = new AbortController()
      const timer = setTimeout(() => controller.abort(), 9000)
      try {
        const context = await fetchContext(controller.signal)
        clearTimeout(timer)
        if (context) {
          await cache.set(CACHE_KEY, context, {
            ttl: CACHE_TTL,
            tags: ['ry-context'],
            name: 'ry-sovereign-context',
          })
        }
      } catch {
        clearTimeout(timer)
      }
    } catch {
      // Background only — ignore all errors
    }
  })()
}

