/**
 * neon-context.ts — Runtime RAG context loader
 *
 * Pulls RY's family profiles, biography, and personal memories from Neon
 * using the native fetch API (Neon HTTP SQL endpoint) — no connection pooling,
 * no package abstraction, AbortController works cleanly.
 *
 * Caches the result in Vercel Runtime Cache for 1h.
 * Hard abort after 2s — never blocks streaming.
 */

import { getCache } from '@vercel/functions'

const CACHE_KEY = 'chyren:ry-context:v2'
const CACHE_TTL = 3600 // 1 hour
const DB_TIMEOUT_MS = 2000

interface NeonRow {
  [key: string]: unknown
}

interface NeonResult {
  rows: NeonRow[]
}

/** Execute a single SQL query via Neon's HTTP SQL API */
async function neonQuery(
  query: string,
  signal: AbortSignal,
  host: string,
  auth: string,
): Promise<NeonRow[]> {
  const resp = await fetch(`https://${host}/sql`, {
    method: 'POST',
    headers: {
